using IntegraRP.Application.Abstractions.Services;using IntegraRP.Infrastructure.Data;using IntegraRP.Infrastructure.Data.Migrations;using IntegraRP.Infrastructure.Services;using Microsoft.Extensions.Configuration;using Microsoft.Extensions.DependencyInjection;
namespace IntegraRP.Infrastructure.DependencyInjection;public static class ServiceCollectionExtensions{public static IServiceCollection AddInfrastructure(this IServiceCollection services,IConfiguration configuration){services.AddSingleton<IDbConnectionFactory,NpgsqlConnectionFactory>();services.AddScoped<IIntegraRpQueries,SeededIntegraRpQueries>();services.AddScoped<IMigrationRunner,PostgresMigrationRunner>();return services;}}
